const crypto = require('crypto');

// Universal Text Extraction
let text = '';
let source = 'WhatsApp';
let sender_id = 'unknown';
let message_id = 'unknown';

if ($json.message && typeof $json.message === 'string') {
  text = $json.message;
  source = 'Telegram_UserBot';
  message_id = $json.message_id || Date.now().toString();
} else if ($json.message && $json.message.text) {
  text = $json.message.text;
  source = 'WhatsApp';
  sender_id = $json.wa_id || ($json.sender ? $json.sender.wa_id : 'unknown');
  message_id = $json.message.message_id || 'unknown';
} else if ($json.text) {
  text = $json.text;
  source = 'Telegram_UserBot';
}

const normalized = text.toLowerCase().replace(/\s+/g, '');
const hash = crypto.createHash('md5').update(normalized).digest('hex');

return [{ json: { ...$json, extracted_text: text, source: source, hash: hash, sender_id: sender_id, msg_id_raw: message_id, sanitized_ts: new Date().toISOString() } }];

